import{_ as o,c as a,o as t,a1 as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"关于: OpenCodeDocs 简介 | opencodedocs","description":"学习 OpenCodeDocs，了解 AI 生态第一教程站。深入解析开源项目，提供源码驱动、100% 可运行的高质量教程。","frontmatter":{"title":"关于: OpenCodeDocs 简介 | opencodedocs","sidebarTitle":"了解项目愿景","subtitle":"关于: OpenCodeDocs 简介 | opencodedocs","description":"学习 OpenCodeDocs，了解 AI 生态第一教程站。深入解析开源项目，提供源码驱动、100% 可运行的高质量教程。"},"headers":[],"relativePath":"zh/about.md","filePath":"zh/about.md"}'),n={name:"zh/about.md"};function s(i,e,c,l,d,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="关于-opencodedocs" tabindex="-1">关于 OpenCodeDocs <a class="header-anchor" href="#关于-opencodedocs" aria-label="Permalink to &quot;关于 OpenCodeDocs&quot;">​</a></h1><blockquote><p><strong>AI 生态第一教程站 · 源码驱动 · 100% 可运行</strong></p></blockquote><h2 id="我们的愿景" tabindex="-1">我们的愿景 <a class="header-anchor" href="#我们的愿景" aria-label="Permalink to &quot;我们的愿景&quot;">​</a></h2><p>AI 工具迭代飞快，官方文档滞后，网上教程过时——我们要改变这一切。</p><p>OpenCodeDocs 深入解析开源项目源码与官方示例，提炼核心逻辑，并通过自动化验证确保每一行代码都能跑通。</p><p>当项目更新时，我们的教程同步更新。每篇教程都清晰标注 Git Commit 版本，让你知道代码基于哪个版本生成。</p><p><strong>我们的目标是成为 AI 工具圈的 &quot;Verified Standard&quot;。</strong></p><h2 id="开源协议" tabindex="-1">开源协议 <a class="header-anchor" href="#开源协议" aria-label="Permalink to &quot;开源协议&quot;">​</a></h2><p>我们相信开放带来信任。欢迎社区贡献、纠错、补充。</p><h3 id="教程内容" tabindex="-1">教程内容 <a class="header-anchor" href="#教程内容" aria-label="Permalink to &quot;教程内容&quot;">​</a></h3><p><strong>协议</strong>: <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a><br> 署名 - 非商业使用 - 相同方式共享。允许转载和改编，但需注明出处，不得用于商业目的，且需以相同协议共享。</p><h3 id="构建工具" tabindex="-1">构建工具 <a class="header-anchor" href="#构建工具" aria-label="Permalink to &quot;构建工具&quot;">​</a></h3><p><strong>VitePress</strong>: 本项目使用 <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> 构建。<br> 感谢 VitePress 团队提供如此优秀的静态网站生成器。</p><p><a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">查看 GitHub 仓库</a></p><h2 id="联系我们" tabindex="-1">联系我们 <a class="header-anchor" href="#联系我们" aria-label="Permalink to &quot;联系我们&quot;">​</a></h2><ul><li><strong>邮箱</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Twitter</strong>: <a href="https://x.com/codingzys" target="_blank" rel="noreferrer">@codingzys</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">github.com/vbgate/opencodedocs</a></li></ul>',16)])])}const g=o(n,[["render",s]]);export{b as __pageData,g as default};
